from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Find benefits.xlsx (case-insensitive)
    benefits_files = list(Path(workspace_path).glob('**/benefits.xlsx'))
    if not benefits_files:
        benefits_files = list(Path(workspace_path).glob('**/Benefits.xlsx'))
    if not benefits_files:
        benefits_files = list(Path(workspace_path).glob('**/*.xlsx'))
        benefits_files = [f for f in benefits_files if 'benefit' in f.name.lower()]
    if not benefits_files:
        return {"pass": False, "score": 0.0, "feedback": "No benefits.xlsx file found in workspace"}

    wb = openpyxl.load_workbook(benefits_files[0])

    bv_complete_found = False
    fc_log_found = False
    bv_complete_value = None
    fc_log_value = None

    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]

        # Collect all cell values into a grid
        all_values = []
        for row in ws.iter_rows():
            row_vals = []
            for c in row:
                row_vals.append(str(c.value).strip() if c.value is not None else '')
            all_values.append(row_vals)

        # Find header positions
        bv_col = None
        fc_col = None
        header_row_idx = None

        for i, row_vals in enumerate(all_values):
            for j, val in enumerate(row_vals):
                upper_val = val.upper().replace(' ', '_')
                if upper_val == 'BV_COMPLETE':
                    bv_col = j
                    if header_row_idx is None:
                        header_row_idx = i
                if upper_val == 'FINANCIAL_COUNSELING_LOG':
                    fc_col = j
                    if header_row_idx is None:
                        header_row_idx = i

        if header_row_idx is not None:
            for row_vals in all_values[header_row_idx + 1:]:
                if bv_col is not None and bv_col < len(row_vals):
                    cell_val = row_vals[bv_col].strip()
                    if cell_val.upper() == 'YES':
                        bv_complete_found = True
                        bv_complete_value = cell_val
                if fc_col is not None and fc_col < len(row_vals):
                    cell_val = row_vals[fc_col].strip()
                    if cell_val:
                        fc_log_value = cell_val
                        # Check for the specific log entry: '03/26/2026 14:36—SUCCESS'
                        # Be lenient: accept various dash types (em dash, en dash, hyphen) and slight formatting
                        normalized = cell_val.upper()
                        # Check contains SUCCESS and the date/time components
                        has_success = 'SUCCESS' in normalized
                        has_date = '03/26/2026' in normalized or '3/26/2026' in normalized
                        has_time = '14:36' in normalized
                        if has_success and has_date and has_time:
                            fc_log_found = True

        # Also do a broad fallback scan: look at column-header mapping approach
        if not bv_complete_found or not fc_log_found:
            # Scan using openpyxl column-header tracking
            col_headers = {}
            for row in ws.iter_rows():
                for cell in row:
                    if cell.value is not None:
                        val_upper = str(cell.value).strip().upper().replace(' ', '_')
                        if val_upper == 'BV_COMPLETE':
                            col_headers[('BV_COMPLETE', cell.column)] = cell.row
                        if val_upper == 'FINANCIAL_COUNSELING_LOG':
                            col_headers[('FINANCIAL_COUNSELING_LOG', cell.column)] = cell.row

            for row in ws.iter_rows():
                for cell in row:
                    if cell.value is None:
                        continue
                    val = str(cell.value).strip()

                    if not bv_complete_found and val.upper() == 'YES':
                        if ('BV_COMPLETE', cell.column) in col_headers:
                            if cell.row > col_headers[('BV_COMPLETE', cell.column)]:
                                bv_complete_found = True
                                bv_complete_value = val

                    if not fc_log_found:
                        if ('FINANCIAL_COUNSELING_LOG', cell.column) in col_headers:
                            if cell.row > col_headers[('FINANCIAL_COUNSELING_LOG', cell.column)]:
                                normalized = val.upper()
                                has_success = 'SUCCESS' in normalized
                                has_date = '03/26/2026' in normalized or '3/26/2026' in normalized
                                has_time = '14:36' in normalized
                                if has_success and has_date and has_time:
                                    fc_log_found = True
                                    fc_log_value = val

    if bv_complete_found and fc_log_found:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"benefits.xlsx has BV_Complete='YES' (found: '{bv_complete_value}') and Financial_Counseling_Log contains '03/26/2026 14:36—SUCCESS' (found: '{fc_log_value}')"
        }

    issues = []
    if not bv_complete_found:
        issues.append(f"BV_Complete is not set to 'YES' (found: '{bv_complete_value}')")
    if not fc_log_found:
        issues.append(f"Financial_Counseling_Log does not contain '03/26/2026 14:36—SUCCESS' (found: '{fc_log_value}')")

    return {
        "pass": False,
        "score": 0.0,
        "feedback": "benefits.xlsx issues: " + "; ".join(issues)
    }

