from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    target_file = Path(workspace_path) / "audit_log.xlsx"
    if not target_file.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File 'audit_log.xlsx' not found in workspace at {workspace_path}."}

    try:
        wb = openpyxl.load_workbook(target_file)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open 'audit_log.xlsx': {e}"}

    # Expected headers per rubric:
    #   'Date', 'Patient_Last_Name', 'Patient_First_Name', 'Patient_DOB',
    #   'Action', 'File_Updated', 'Fields_Updated', 'New_Value', 'Staff_User',
    #   'Result' (or 'Result (SUCCESS/FAILED/STOP—reason)')
    #
    # We accept underscores or spaces interchangeably and are case-insensitive.
    expected_headers = [
        ('Date', ['date']),
        ('Patient_Last_Name', ['patient last name', 'patient_last_name']),
        ('Patient_First_Name', ['patient first name', 'patient_first_name']),
        ('Patient_DOB', ['patient dob', 'patient_dob']),
        ('Action', ['action']),
        ('File_Updated', ['file_updated', 'file updated']),
        ('Fields_Updated', ['fields_updated', 'fields updated']),
        ('New_Value', ['new_value', 'new value']),
        ('Staff_User', ['staff_user', 'staff user']),
        ('Result', None),  # Special handling: any header starting with 'result'
    ]

    def normalize(s):
        if s is None:
            return None
        return ' '.join(s.strip().lower().split())

    def check_headers(ws):
        actual_headers_raw = []
        for cell in ws[1]:
            val = cell.value
            if val is not None:
                actual_headers_raw.append(str(val).strip())
            else:
                actual_headers_raw.append(None)

        actual_normalized = [normalize(h) for h in actual_headers_raw]

        missing = []
        for display_name, variants in expected_headers:
            found = False
            for act in actual_normalized:
                if act is None:
                    continue
                if display_name == 'Result':
                    if act == 'result' or act.startswith('result'):
                        found = True
                        break
                else:
                    act_underscored = act.replace(' ', '_')
                    act_spaced = act.replace('_', ' ')
                    for v in variants:
                        v_underscored = v.replace(' ', '_')
                        v_spaced = v.replace('_', ' ')
                        if act in (v, v_underscored, v_spaced) or act_underscored in (v, v_underscored) or act_spaced in (v, v_spaced):
                            found = True
                            break
                    if found:
                        break
            if not found:
                missing.append(display_name)

        return missing, actual_headers_raw

    # Check ALL sheets
    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]
        missing, actual_headers_raw = check_headers(ws)
        if not missing:
            return {
                "pass": True,
                "score": 1.0,
                "feedback": f"All required headers found in 'audit_log.xlsx' (sheet '{sheet_name}'). Headers found: {actual_headers_raw}."
            }

    # If we get here, no sheet had all headers. Report missing from active sheet.
    ws = wb.active
    missing, actual_headers_raw = check_headers(ws)

    return {
        "pass": False,
        "score": 0.0,
        "feedback": f"Missing headers in 'audit_log.xlsx': {missing}. Checked all sheets ({wb.sheetnames}). Headers found in active sheet (raw): {actual_headers_raw}."
    }

from pathlib import Path
import openpyxl
import re
import datetime


def verify(workspace_path, external_services_path=None):
    ws = Path(workspace_path)
    target_file = ws / "audit_log.xlsx"

    if not target_file.exists():
        return {
            "pass": False,
            "score": 0.0,
            "feedback": (
                f"File 'audit_log.xlsx' not found in workspace. "
                f"Files present: {[f.name for f in ws.iterdir()]}"
            ),
        }

    try:
        wb = openpyxl.load_workbook(str(target_file))
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open audit_log.xlsx: {e}"}

    # Search all sheets
    for sheet_name in wb.sheetnames:
        ws_sheet = wb[sheet_name]

        # Build header map from row 1
        headers = {}
        for col_idx, cell in enumerate(ws_sheet[1], start=1):
            if cell.value is not None:
                headers[str(cell.value).strip().lower()] = col_idx

        if not headers:
            continue

        # ---------------------------------------------------------------------------
        # find_col uses exact normalized matching (with underscore/space
        # interchangeability). This avoids 'date' matching 'file_updated' etc.
        # ---------------------------------------------------------------------------
        def find_col(possible_names):
            for name in possible_names:
                nl = name.lower().strip()
                nl_u = nl.replace(" ", "_")
                nl_s = nl.replace("_", " ")
                for h, idx in headers.items():
                    h_u = h.replace(" ", "_")
                    h_s = h.replace("_", " ")
                    if h in (nl, nl_u, nl_s) or h_u in (nl, nl_u, nl_s) or h_s in (nl, nl_u, nl_s):
                        return idx
            return None

        col_date          = find_col(["date"])
        col_action        = find_col(["action"])
        col_file_updated  = find_col(["file_updated", "file updated"])
        col_fields_updated = find_col(["fields_updated", "fields updated"])
        col_new_value     = find_col(["new_value", "new value"])
        col_result        = find_col(["result"])
        col_last_name     = find_col(["patient last name", "patient_last_name", "patient last  name", "patient_last _name"])
        col_first_name    = find_col(["patient first name", "patient_first_name"])
        col_dob           = find_col(["patient_dob", "patient dob"])

        # Iterate data rows (row 2 onward)
        for row_idx in range(2, ws_sheet.max_row + 1):

            def get_val(col, _row=row_idx):
                if col is None:
                    return None
                v = ws_sheet.cell(row=_row, column=col).value
                if v is None:
                    return ""
                return str(v).strip()

            date_val          = get_val(col_date)
            action_val        = get_val(col_action)
            file_updated_val  = get_val(col_file_updated)
            fields_updated_val = get_val(col_fields_updated)
            new_value_val     = get_val(col_new_value)
            result_val        = get_val(col_result)
            last_name_val     = get_val(col_last_name)
            first_name_val    = get_val(col_first_name)
            dob_val           = get_val(col_dob)

            # ── Date: must be 03/26/2026 ────────────────────────────────────────
            date_ok = False
            if col_date:
                raw_cell = ws_sheet.cell(row=row_idx, column=col_date).value
                if isinstance(raw_cell, (datetime.datetime, datetime.date)):
                    if raw_cell.month == 3 and raw_cell.day == 26 and raw_cell.year == 2026:
                        date_ok = True
                if not date_ok:
                    date_norm = (date_val or "").replace("-", "/").strip()
                    if "03/26/2026" in date_norm or "3/26/2026" in date_norm:
                        date_ok = True
            else:
                date_ok = True  # no date column found; be lenient

            if not date_ok:
                continue

            # ── Action: must contain 'financial counseling complete' ────────────
            if not action_val or "financial counseling complete" not in action_val.lower():
                continue

            # ── File_Updated: must reference benefits.xlsx ──────────────────────
            if not file_updated_val or "benefits" not in file_updated_val.lower():
                continue

            # ── Fields_Updated: must contain both column names ──────────────────
            if not fields_updated_val:
                continue
            fu_lower = fields_updated_val.lower().replace(" ", "_")
            if "financial_counseling_log" not in fu_lower:
                continue
            if "bv_complete" not in fu_lower:
                continue

            # ── New_Value: must contain the exact timestamp+status string and YES ─
            # We normalise em-dash / en-dash to a plain hyphen for comparison so that
            # dash-encoding differences do not cause spurious failures.
            if not new_value_val:
                continue
            nv_normalised = (
                new_value_val
                .replace("\u2014", "-")   # em dash
                .replace("\u2013", "-")   # en dash
            )
            # The required substring is '03/26/2026 14:36—SUCCESS'; after normalisation
            # it becomes '03/26/2026 14:36-SUCCESS'.
            has_timestamp_success = (
                "03/26/2026 14:36-success" in nv_normalised.lower()
                or "03/26/2026 14:36\u2014success" in new_value_val.lower()
            )
            if not has_timestamp_success:
                continue
            if "yes" not in new_value_val.lower():
                continue

            # ── Result: must be exactly 'SUCCESS' (case-insensitive) ────────────
            if not result_val or result_val.upper() != "SUCCESS":
                continue

            # ── Patient names ────────────────────────────────────────────────────
            if not last_name_val or last_name_val.lower() != "lopez":
                continue
            if not first_name_val or first_name_val.lower() != "kevin":
                continue

            # ── Patient DOB: must be '11091990' with NO separators ───────────────
            if not dob_val:
                continue
            dob_clean = dob_val.strip()

            # Fail explicitly if separators are present
            if re.search(r"[/\\\-\. ]", dob_clean):
                return {
                    "pass": False,
                    "score": 0.0,
                    "feedback": (
                        f"Found a matching row at row {row_idx} in sheet '{sheet_name}' "
                        f"but Patient_DOB '{dob_clean}' contains separators. "
                        f"It must be exactly '11091990' with no separators."
                    ),
                }

            # Handle numeric storage by Excel (e.g. 11091990.0 -> '11091990')
            dob_to_check = dob_clean
            try:
                dob_to_check = str(int(float(dob_clean)))
            except (ValueError, TypeError):
                pass

            if dob_to_check != "11091990":
                continue

            # ── All checks passed ────────────────────────────────────────────────
            return {
                "pass": True,
                "score": 1.0,
                "feedback": (
                    f"Found matching row in sheet '{sheet_name}' at row {row_idx}. "
                    f"Date='{date_val}', Action='{action_val}', "
                    f"File_Updated='{file_updated_val}', Fields_Updated='{fields_updated_val}', "
                    f"New_Value='{new_value_val}', Result='{result_val}', "
                    f"Last Name='{last_name_val}', First Name='{first_name_val}', "
                    f"DOB='{dob_val}'."
                ),
            }

    # ── No matching row found — return diagnostics ────────────────────────────
    diag = []
    for sheet_name in wb.sheetnames:
        ws_sheet = wb[sheet_name]
        diag.append(
            f"Sheet '{sheet_name}': {ws_sheet.max_row} rows, "
            f"headers: {[str(c.value) for c in ws_sheet[1]]}"
        )
        for row_idx in range(2, min(ws_sheet.max_row + 1, 10)):
            row_vals = [
                str(ws_sheet.cell(row=row_idx, column=c).value)
                for c in range(1, ws_sheet.max_column + 1)
            ]
            diag.append(f"  Row {row_idx}: {row_vals}")

    return {
        "pass": False,
        "score": 0.0,
        "feedback": (
            "No matching row found in audit_log.xlsx meeting all criteria "
            "(Date='03/26/2026', Action='Financial Counseling Complete', "
            "File_Updated='Benefits.xlsx', Fields_Updated containing "
            "'Financial_Counseling_Log' and 'BV_Complete', New_Value containing "
            "'03/26/2026 14:36\u2014SUCCESS' and 'YES', Result='SUCCESS', "
            "Patient Last Name='Lopez', Patient First Name='Kevin', "
            "Patient_DOB='11091990'). "
            f"Diagnostics: {'; '.join(diag)}"
        ),
    }

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "audit_log.xlsx"

    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File 'audit_log.xlsx' not found in workspace at {workspace_path}."}

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open 'audit_log.xlsx': {e}"}

    total_data_rows = 0
    details = []

    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]
        all_rows = list(ws.iter_rows(values_only=True))

        # Filter out completely empty rows
        non_empty_rows = [row for row in all_rows if any(cell is not None and str(cell).strip() != '' for cell in row)]

        if len(non_empty_rows) == 0:
            details.append(f"Sheet '{sheet_name}': no non-empty rows.")
            continue

        # First non-empty row is assumed to be the header
        header_row = non_empty_rows[0]
        data_rows = non_empty_rows[1:]
        num_data = len(data_rows)
        total_data_rows += num_data
        details.append(f"Sheet '{sheet_name}': header={header_row}, {num_data} data row(s): {data_rows}")

    detail_str = " | ".join(details)

    if total_data_rows == 1:
        return {"pass": True, "score": 1.0, "feedback": f"audit_log.xlsx has exactly 1 data row (excluding headers) across all sheets. {detail_str}"}
    else:
        return {"pass": False, "score": 0.0, "feedback": f"audit_log.xlsx has {total_data_rows} total data row(s) across all sheets (expected exactly 1). {detail_str}"}
